if ( v == 0 ) v = 1;
if ( v > 249) v = 249 ;

	if ( ph_error >= 2048 )
		{
		XtSetArg(args[0], XmNwidth, v);
		XtSetArg(args[1], XmNleftOffset, 250);
		}
	if ( ph_error < 2048 )
		{
                XtSetArg(args[0], XmNwidth, v);
                XtSetArg(args[1], XmNleftOffset, 250 - v);
		}

	XtSetValues(label109, args, 2);


