carica_chopper()
{
    Boolean argok;
    char cmd[20];
    char frame_to_s[1024], frame_to_r[1024] ;
    int nb_to_s, nb_to_r ;
    int valore;

    switch ( chopper_onoff )
        {
        case SPENTO :

        bit_set(chopper_fildes, chopper_par_io_port, chopper_onoff_bit);

        break;

        case ACCESO :

        bit_clear(chopper_fildes, chopper_par_io_port, chopper_onoff_bit);

        break;

        }


    switch ( chopper_intext )
        {
        case SPENTO :
        /* esterno */


        bit_set(chopper_fildes, chopper_par_io_port, chopper_intext_bit);
        break;

        case ACCESO :
        /* interno */


        bit_clear(chopper_fildes, chopper_par_io_port, chopper_intext_bit);
        break;

        }



valore=(int)chopper_m_d;
scriviporta(chopper_fildes, chopper_m_d_port, valore);

valore=(int)chopper_d_c;
scriviporta(chopper_fildes, chopper_d_c_port, valore);

valore=(int)chopper_p_w;
scriviporta(chopper_fildes, chopper_p_w_port, valore);

valore=(int)chopper_phase;
scriviporta(chopper_fildes, chopper_phase_port, valore);

if ( chopper_denom > 7 )
		{
                /*invio il comando slow pulsing on */
                bit_set(chopper_fildes, chopper_par_io_port, chopper_spfp_bit);
		}
else
		{
                /*invio il comando slow pulsing off */
                bit_clear(chopper_fildes, chopper_par_io_port, chopper_spfp_bit);
		}

}



auto_zero()
{
int cnt;

char cmd[64];
char stringa[64];
char stringa1[64];
char namestring[64];
char frame_to_r[1024];

int nb_to_s, nb_to_r;
int valore;

int ph_error, amp_error, freq_error;
int label_x, label_lungh;
int error_ph;

Arg args[20];
static int aa = 0;

int ds_1, ds_2, nuovo_qp;

float deriv;

nb_to_s = sizeof(cmd);
nb_to_r = sizeof(frame_to_r);

aa = aa + 1 ;
if ( aa == 5 ) aa = 0;

for (cnt = 0 ; cnt < max_sp; cnt++)
	{
	if (soft_verbose) printf ("corr = %d su %s", da_corr[cnt], etichetta[cnt]);
	if ( zero_f_onoff[cnt] == 1 && ( aa == 0 || da_corr[cnt] == 1 ) ) 
		{
		if (soft_verbose) printf ("correzione frequenza su %s", etichetta[cnt]);

        	strcpy(cmd,"!PHA?");

     		/* write to server */
        	if (  write(rf_fildes[cnt],cmd,sizeof(cmd)) < 0 )
            		perror( "\nclient: error writing to s streamsocket\n" ) ;
        	if (net_verbose) printf (" scritto %s su   %d\n", cmd, rf_fildes[cnt]);

     		/* listen to server */
        	if ( read( rf_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
            		perror( "\nclient: error reading from s streamsocket\n" ) ;
        	if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, rf_fildes[cnt]);

		if ( strncmp (frame_to_r, "Not Done", 8) == 0)
        		{
        		rf_is_alive[cnt] = 0;
        		pdr = cnt;
        		refresh();
        		}

        	error_ph = atoi(frame_to_r);

		if ( error_ph > 2048 + zero_f_soglia[cnt] )
			{
			if (soft_verbose) printf ("correzione >\n");

			sprintf(stringa,"!%1d, -%d, %d",motor[cnt], zero_f_step[cnt], 100);

			if (net_verbose) printf ("scrivo il comando %s nel canale %d\n", stringa, za_fildes[cnt]);

     			/* write to server */
        		if (  write(za_fildes[cnt],stringa,sizeof(stringa)) < 0 )
            			perror( "\nclient: error writing to s streamsocket\n" ) ;
        		if (net_verbose) printf (" scritto %s su   %d\n", stringa, za_fildes[cnt]);

     			/* listen to server */
        		if ( read( za_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
            			perror( "\nclient: error reading from s streamsocket\n" ) ;
        		if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, za_fildes[cnt]);

			if ( strncmp (frame_to_r, "Not Done", 8) == 0)
        			{
        			tu_is_alive[cnt] = 0;
        			pdr = cnt;
        			refresh();
        			}
			}

                if ( error_ph < 2048 - zero_f_soglia[cnt] )
                        {
                        if (soft_verbose) printf ("correzione <\n");

                        sprintf(stringa,"!%1d, %d, %d",motor[cnt], zero_f_step[cnt], 100);

                        if (net_verbose) printf ("scrivo il comando %s nel canale %d\n", stringa, za_fildes[cnt]);


                        /* write to server */
                        if (  write(za_fildes[cnt],stringa,sizeof(stringa)) < 0 )
                                perror( "\nclient: error writing to s streamsocket\n" ) ;
                        if (net_verbose) printf (" scritto %s su   %d\n", stringa, za_fildes[cnt]);

                        /* listen to server */
                        if ( read( za_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
                                perror( "\nclient: error reading from s streamsocket\n" ) ;
                        if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, za_fildes[cnt]);

                        if ( strncmp (frame_to_r, "Not Done", 8) == 0)
                                {
                                tu_is_alive[cnt] = 0;
                                pdr = cnt;
                                refresh();
                                }
                        }

		}

	if ( zero_a_onoff[cnt] == 1 && ( aa == 0 || da_corr[cnt] == 1 ) ) 
		{
		if (soft_verbose) printf ("correzione ampiezza  su %s", etichetta[cnt]);


		/* error_amp2[cnt] e' l'errore DOPO la misurazione e dopo aver variato qp */
		/* error_amp1[cnt] e' l'errore del giro precedente */

        	strcpy(cmd,"!AMP?");

     		/* write to server */
        	if (  write(rf_fildes[cnt],cmd,sizeof(cmd)) < 0 )
            		perror( "\nclient: error writing to s streamsocket\n" ) ;

        	if (net_verbose) printf (" scritto %s su   %d\n", cmd, rf_fildes[cnt]);

     		/* listen to server */
        	if ( read( rf_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
            		perror( "\nclient: error reading from s streamsocket\n" ) ;

        	if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, rf_fildes[cnt]);

		if ( strncmp (frame_to_r, "Not Done", 8) == 0)
        		{
        		rf_is_alive[cnt] = 0;
        		pdr = cnt;
        		refresh();
        		}

/*mn/*
        	error_amp1[cnt] = error_amp2[cnt];
        	error_amp2[cnt] = 2048 - atoi(frame_to_r);
		if (soft_verbose) printf ("\n deltae = %f step[cnt] = %d error_amp1[cnt] = %d e2 = %d\n", deltae, step[cnt], error_amp1[cnt], error_amp2[cnt]);
		if ( (error_amp2[cnt] >= zero_a_soglia[cnt]) || (error_amp2[cnt] <= 0 - zero_a_soglia[cnt]))
			{
			/* il nuovo errore e' fouri dalla soglia */
			/* vado a vedere quello del giro precedente */
			if (soft_verbose) printf ("il nuovo errore e' fouri dalla soglia\n");

			if ( (error_amp1[cnt] >= zero_a_soglia[cnt]) || (error_amp1[cnt] <= 0 - zero_a_soglia[cnt]))
				{
				/* anche l'errore del giro precedente era fuori */
				/* devo calcolare il valore di step */
				if (soft_verbose) printf ("devo calcolare il valore di step\n");
				
				if ( abs(error_amp2[cnt]) >= abs(error_amp1[cnt]) )
					{
					/* passo troppo lungo ma nella direzione giusta */
					/* dimezzo il passo */
					if (soft_verbose) printf ("|E2| > |E1|\n");
					if( step[cnt] >= 2*zero_a_step[cnt] ) step[cnt] = (int)(step[cnt]/2.0);
					step[cnt] = 0 - step[cnt] ;
					}
				else
					{
					if (error_amp2[cnt]==0) error_amp2[cnt]=1;
					deltae = ((float)error_amp2[cnt] - (float)error_amp1[cnt])/(float)error_amp2[cnt];
					if (soft_verbose) printf ("deltae = %f fabsf(deltae) = %f\n", deltae, fabsf(deltae));
					
					if ( fabsf(deltae) <= 0.25) 
						{
						if (soft_verbose) printf ("raddoppio step\n");
						step[cnt] = 2 * step[cnt] ;
						}

					if ( fabsf(deltae) > 1.4 )
						{
						if (soft_verbose) printf ("dimezzo step\n");
						if( step[cnt] >= 2*zero_a_step[cnt] ) step[cnt] = (int)(step[cnt]/2.0);
						}

					if ( deltae > 0 ) step[cnt] = 0 - step[cnt];
					}

				}
			else
				{
				/* l'errore del giro precedente era nella soglia */
				/* inizializzo step */
				if (soft_verbose) printf ("inizializzo step\n");
				step[cnt] =  zero_a_step[cnt];
				}

			if ( error_amp2[cnt] <= 0 )
				valore = (int)((power[cnt]/500.0)*4096.0+abs(step[cnt]));
			else
				valore = (int)((power[cnt]/500.0)*4096.0-abs(step[cnt]));

			nuovo_qp = (int)(valore*500.0/4096.0);
			power[cnt] = nuovo_qp;

                        sprintf(stringa,"%4d",valore);
                        strcpy(cmd,"!DAC3=");
                        strcat(cmd,stringa);

                        /* write to server */

                        if (  write(rf_fildes[cnt],cmd,sizeof(cmd)) < 0 )
                                perror( "\nclient: error writing to s streamsocket\n" ) ;

                        if (net_verbose) printf (" scritto %s su   %d\n", cmd, rf_fildes[cnt]);

                        /* listen to server */

                        if ( read( rf_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
                                perror( "\nclient: error reading from s streamsocket\n" ) ;


                        /* aggiorno posizione del cursore e scritte etichetta */

                        sprintf(stringa1,"%4d",power[sottop_selez]*100/500);
                        strcpy(namestring,"power : ");
                        strcat(namestring,stringa1);

                        XtSetArg(args[0], XmNlabelString, XmStringCreate(namestring, XmFONTLIST_DEFAULT_TAG));

                        if ( prec_sottop_selez != 9999 )
                                {
                                if ( sottop_tipo[sottop_selez] == 0 )
                                        {
                                        /* BUNCHER */
                                        XmScrollBarSetValues (scrollBar17, power[sottop_selez], 26, 1, 10, FALSE);
                                        XtSetValues(label71, args, 1);
                                        }
                                else
                                        {
                                        /* POSTCHOPPER */
                                        XmScrollBarSetValues (scrollBar6, power[sottop_selez], 26, 1, 10, FALSE);
                                        XtSetValues(label125, args, 1);
                                        }
                                }
#ifdef ASDF
			if ( sottop_tipo[sottop_selez] == 0 )
				{
				/* sto lavorando con il buncher */
				/* vedo se variare l'attenuazione */
                                if ( power[cnt] > 500.0 * 70.0 / 100.0 )
					{
                                        /* diminuire l'attenuazione */
					if (soft_verbose) printf ("------------ diminuisco attenuazione \n");
                                        if (attenuation[cnt] < 32)
						attenuation[cnt] = attenuation[cnt] + 1;
                                        }

				if ( power[cnt] < 500.0 * 30.0 / 100.0 )
					{
			        	/* aumentare l'attenuazione */
					if (soft_verbose) printf ("+++++++++++++++ aumento attenuazione \n");
			        	if (attenuation[cnt] > 0)
						attenuation[cnt] = attenuation[cnt] - 1;
			        	}


                        	if ( prec_sottop_selez != 9999 )
                                	{
					sprintf(stringa1,"-%d",64-attenuation[sottop_selez]*2);
					strcpy(namestring,"atten. (dB): ");
					strcat(namestring,stringa1);
					XtSetArg(args[0], XmNlabelString, XmStringCreate(namestring, XmFONTLIST_DEFAULT_TAG));
					XmScrollBarSetValues (scrollBar17, attenuation[sottop_selez], 26, 1, 10, FALSE);
					XtSetValues(label75, args, 1);
					}

				/* trasmetto al controller il valore dell'attenuazione */

				valore=32-attenuation[cnt];
				sprintf(stringa,"%4d",valore);

				strcpy(cmd,"!EXTPS=");
				strcat(cmd,stringa);

			     	/* write to server */
			        if (  write(rf_fildes[cnt],cmd,sizeof(cmd)) < 0 )
			            {
			            perror( "\nclient: error writing to s streamsocket\n" ) ;
			            }
			        if (net_verbose) printf (" scritto %s su   %d\n", cmd, rf_fildes[cnt]);

			     	/* listen to server */
			        if ( read( rf_fildes[cnt], frame_to_r, nb_to_r ) < 0 )
			            {
			            perror( "\nclient: error reading from s streamsocket\n" ) ;
			            }
			        if (net_verbose) printf (" letto %s da   %d\n", frame_to_r, rf_fildes[cnt]);

				if ( strncmp (frame_to_r, "Not Done", 8) == 0)
			        	{
			        	rf_is_alive[cnt] = 0;
			        	pdr = sottop_selez;
			        	refresh();
			        	errore();
			        	}
				}

#endif
			}
		else
			{
			/* il nuovo errore e' nella soglia: non faccio niente */
			if (soft_verbose) printf ("ampiezza: =\n");
			}
		}
	

if ( auto_zero_onoff ) XtAppAddTimeOut(XtWidgetToApplicationContext(bulletinBoard), 600, auto_zero, NULL);
}

